-- 修改会议讲者验证trigger
UPDATE `object_validations` SET `trigger_code` = '# object_name = sender._meta.db_table\n# if object_name == \'event_speakers\' and event == \'pre_save\':\nmsg = \'\'\n# 1. 单会议的讲者使用限制\n# 讲者级别	单次费用限制（含）	全年单一讲者讲课费支付上限	年度使用次数	特殊规则\n# 城市级	1300~3200	<=120000	<25次	城市级讲者在科室会内讲课，单次不超过1300\n# 区域级	2500~5000	<=150000	<25次\n# 全国级	3800~7500	<=200000	<25次\n\nif instance.speaker_level.label == u\'城市级\':\n    if instance.speaker_expense > 3200:\n        msg += u\'城市级讲者（%s）单次费用限制0~3200\' % instance.speaker.name\n    # 科室会的特殊规则\n    if instance.event.record_type.name in (\'cs_department\',\'cs_department__report\'):\n        if instance.speaker_expense > 1300:\n            msg += u\'城市级讲者（%s）在学术推广会议-科室会/院内会内讲课，单次不超过1300\' % instance.speaker.name\nif instance.speaker_level.label == u\'区域级\':\n    if instance.speaker_expense > 5000:\n        msg += u\'区域级讲者（%s）单次费用限制0~5000\' % instance.speaker.name\nif instance.speaker_level.label == u\'全国级\':\n    if instance.speaker_expense > 7500:\n        msg += u\'全国级讲者（%s）单次费用限制0~7500\' % instance.speaker.name\nif msg:\n    raise create_validation_trigger_rule_errors(msg)' WHERE (`id` = '87451b14-bce1-1234-8758-020652a9390e');
-- 修改地区经理拜访
